+  background: #ffffff;
+  font-family: Arial, sans-serif;
+}
+
+.intro-overlay {
+  position: fixed;
+  inset: 0;
+  z-index: 100;
+  display: grid;
+  place-items: center;
+  width: 100%;
+  border: 0;
+  padding: 24px;
+  background: rgba(255, 255, 255, 0.90);
+  backdrop-filter: blur(22px);
+  -webkit-backdrop-filter: blur(22px);
+  cursor: pointer;
+}
+
+.intro-overlay.is-hidden {
+  display: none;
+}
+
+.intro-overlay__text {
+  color: #000000;
+  font-size: 16px;
+  line-height: 1.4;
+  text-align: center;
+}
+
+#press-to-start {
+  color: rgba(0, 0, 0, 0.25);
+}
+
+.device {
+  width: 80%;
+  min-height: 900px;
+  padding: 70px 90px 80px;
+  background: #DCDCDC;
+  display: flex;
+  flex-direction: column;
+  gap: 68px;
+}
+
+.screen {
