+  border-radius: 16px;
+  width: 100%;
+  height: 600px;
+  background: #000;
+  overflow: hidden;
+}
+
+.screen-visualizer {
+  position: absolute;
+  inset: 0;
+  width: 100%;
+  height: 100%;
+  display: block;
+  pointer-events: none;
+  z-index: 0;
+}
+
+.screen-bar {
+  position: relative;
+  z-index: 2;
+  width: 100%;
+  display: grid;
+  grid-template-columns: 1fr auto 1fr;
+  align-items: start;
+  gap: 46px;
+  padding: 34px 42px 0;
+  color: #f1f1f1;
+}
+
+.recording-timer {
+  position: absolute;
+  left: 50%;
+  bottom: 42px;
+  z-index: 3;
+  padding: 12px 24px;
+  border-radius: 999px;
+  transform: translateX(-50%);
+  background: rgba(255, 255, 255, 0.102);
+  color: rgba(255, 255, 255, 0.82);
+  font-size: 0.8rem;
+  text-align: center;
+  backdrop-filter: blur(10px);
+  -webkit-backdrop-filter: blur(10px);
+  pointer-events: none;
+}
+
+.stats {
+  display: flex;
+  flex-direction: column;
+  justify-self: start;
+  gap: 6px;
+  font-size: 0.8rem;
+}
+
+.stat-pink {
+  color: hsl(289, 100%, 87%);
+}
+
+.stat-green {
+  color: #b0ffbe;
+}
+
+.stat-blue {
+  color: #9cd1ff;
+}
+
+.status {
+  justify-self: center;
+  text-align: center;
+  font-size: 1.5rem;
+  font-weight: 400;
+  letter-spacing: 0.02em;
+  line-height: 1;
+}
+
+.screen-controls {
+  justify-self: end;
+  display: flex;
+  flex-direction: column;
+  align-items: stretch;
+  gap: 10px;
+}
+
+.archive-toggle {
+  display: inline-flex;
+  align-items: center;
+  gap: 16px;
+  border: 0;
+  padding: 0;
+  background: transparent;
+}
+
+.archive-toggle__switch {
+  position: relative;
+  width: 32px;
+  height: 18px;
+  border-radius: 999px;
+  background: #ffffff4a;
+  transition: background-color 160ms ease, box-shadow 160ms ease;
+}
+
+.archive-toggle__thumb {
+  position: absolute;
+  top: 1px;
+  left: 1px;
+  width: 16px;
+  height: 16px;
+  border-radius: 50%;
+  background: #000000;
+  transition: transform 160ms ease, background-color 160ms ease;
+}
+
+.archive-toggle__label {
+  color: rgb(255, 255, 255);
+  font-size: 1.1rem;
+  line-height: 1;
+}
+
+.archive-hint {
+  align-self: center;
+  position: relative;
+  width: 28px;
+  height: 36px;
+  opacity: 0;
+}
+
+.archive-hint::before,
+.archive-hint::after {
+  content: "";
+  position: absolute;
+  left: 50%;
+  top: 0;
+  background: rgba(255, 255, 255, 0.78);
+  transform: translateX(-50%);
+}
+
+.archive-hint::before {
+  width: 6px;
+  height: 30px;
+  border-radius: 999px;
+}
+
+.archive-hint::after {
+  top: 0;
+  width: 18px;
+  height: 18px;
+  background: transparent;
+  border-top: 6px solid rgba(255, 255, 255, 0.78);
+  border-left: 6px solid rgba(255, 255, 255, 0.78);
+  transform: translateX(-50%) rotate(45deg);
+}
+
+.archive-hint.is-pulsing {
+  animation: archiveHintPulse 0.24s ease-in-out 3;
+}
+
+@keyframes archiveHintPulse {
+  0%,
+  100% {
+    opacity: 0;
+  }
+
+  50% {
+    opacity: 1;
+  }
+}
+
+.archive-toggle.is-active .archive-toggle__thumb {
+  transform: translateX(14px);
+}
+
+.archive-toggle.is-active .archive-toggle__switch {
+  background: #ffffff;
+}
+
+.archive-toggle.is-focused .archive-toggle__switch {
+  box-shadow: 0 0 0 1px rgba(255, 255, 255, 0.42);
+}
+
+.archive-panel {
+  position: absolute;
+  bottom: 0;
+  right: 0;
+  width: 530px;
+  height: 223px;
+  padding: 20px 20px 0px 20px;
+  border-radius: 16px 0 0 0;
+  background: rgba(255, 255, 255, 0.12);
+  backdrop-filter: blur(24px);
+  -webkit-backdrop-filter: blur(24px);
+  color: rgba(255, 255, 255, 0.82);
+  opacity: 0;
+  transform: translateX(100%);
+  transition: transform 220ms ease, opacity 220ms ease;
+  z-index: 4;
+  pointer-events: none;
+}
+
+.archive-panel__scroller {
+  height: 100%;
+  overflow-y: auto;
+  overflow-x: hidden;
+  direction: rtl;
+  padding-left: 24px;
+  scrollbar-width: thin;
+  scrollbar-color: rgba(255, 255, 255, 0.38) transparent;
+}
+
+.archive-panel__scroller::-webkit-scrollbar {
+  width: 12px;
+}
+
+.archive-panel__scroller::-webkit-scrollbar-track {
+  background: transparent;
+}
+
+.archive-panel__scroller::-webkit-scrollbar-thumb {
+  border-radius: 999px;
+  background: rgba(255, 255, 255, 0.32);
+}
+
+.archive-panel__list {
+  direction: ltr;
+  display: grid;
+  gap: 12px;
+}
+
+.archive-card {
+  width: 100%;
+  min-height: 47px;
+  padding: 12px 12px;
+  border-radius: 12px;
+  background: rgba(255, 255, 255, 0.08);
+  display: grid;
+  grid-template-columns: 14px 1fr auto;
+  align-items: center;
+  gap: 16px;
+}
+
+.archive-card__mark {
+  width: 14px;
+  height: 14px;
+  border-radius: 50%;
+  background: #ff4949;
+}
+
+.archive-card--success .archive-card__mark {
+  background: #b6ff6e;
+}
+
+.archive-card__wave {
+  width: 100%;
+  height: 18px;
+  object-fit: contain;
+  opacity: 0.9;
+}
+
+.archive-card__duration {
+  display: inline-flex;
+  align-items: center;
+  gap: 8px;
+  color: rgba(255, 255, 255, 0.6);
+  font-size: 14px;
+  line-height: 1;
+}
+
+.archive-card__clock {
+  width: 14px;
+  height: 14px;
+  border-radius: 50%;
+  border: 2px solid currentColor;
+  position: relative;
+}
+
+.archive-card__clock::before,
+.archive-card__clock::after {
+  content: "";
+  position: absolute;
+  left: 50%;
+  top: 50%;
+  background: currentColor;
+  transform-origin: bottom center;
+}
+
+.archive-card__clock::before {
+  width: 2px;
+  height: 4px;
+  transform: translate(-50%, -100%);
+}
+
+.archive-card__clock::after {
+  width: 4px;
+  height: 2px;
+  transform: translate(0, -50%);
+}
+
+.screen.is-archive-open .archive-panel {
+  opacity: 1;
+  transform: translateX(0);
+  pointer-events: auto;
+}
+
+.volume {
+  display: flex;
+  align-items: center;
+  gap: 16px;
+}
+
+.volume-icon {
+  position: relative;
+  width: 10px;
+  height: 10px;
+  flex: 0 0 auto;
+}
+
+.volume-icon::before {
+  content: "";
+  position: absolute;
+  left: 0;
+  top: 0px;
+  width: 8px;
+  height: 10px;
+  background: #7e7e7e;
+  clip-path: polygon(0 25%, 55% 25%, 100% 0, 100% 100%, 55% 75%, 0 75%);
+}
+
+.volume-icon::after {
+  content: "";
+  position: absolute;
+  left: 10px;
+  top: -2px;
+  width: 5px;
+  height: 14px;
+  border-right: 3px solid #7e7e7e;
+  border-radius: 50%;
+}
+
+.volume-track {
+  flex: 1;
+  height: 4px;
+  border-radius: 999px;
+  background: #1d1d1d;
+  position: relative;
+  overflow: hidden;
+}
+
+.volume-fill {
+  position: absolute;
+  inset: 0 auto 0 0;
+  width: 42%;
+  border-radius: inherit;
+  background: linear-gradient(90deg, #8b8b8b, #5f5f5f);
+}
+
+.timeline {
+  position: absolute;
+  left: 34px;
+  right: 34px;
+  bottom: 28px;
+  padding: 28px 34px 18px;
+  border-radius: 0 0 30px 30px;
+  z-index: 2;
+}
+
+.timeline-track {
+  position: relative;
+  display: grid;
+  grid-template-columns: auto repeat(6, 1fr auto);
+  align-items: end;
+  color: rgba(255, 255, 255, 0.52);
+  font-size: 1rem;
+}
+
+.tick-label {
+  position: relative;
+  z-index: 1;
+}
+
+.tick-gap {
+  position: relative;
+  min-width: 110px;
+  height: 14px;
+  margin: 0 8px 3px;
+}
+
+.tick-gap::before,
+.tick-gap::after {
+  content: "";
+  position: absolute;
+  top: 3px;
+  width: 2px;
+  height: 6px;
+  border-radius: 999px;
+  background: rgba(255, 255, 255, 0.52);
+}
+
+.tick-gap::before {
+  left: calc(15% - 1px);
+  box-shadow: 40px 0 0 rgba(255, 255, 255, 0.52);
+}
+
+.tick-gap::after {
+  left: calc(85% - 1px);
+}
+
+.tick-label:last-child {
+  text-align: right;
+}
+
+.controls-row {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: 40px;
+}
+
+.knobs {
+  display: flex;
+  gap: 72px;
+}
+
+.knob {
+  --knob-angle: -93.333deg;
+  position: relative;
+  width: 200px;
+  aspect-ratio: 1;
+  border: 3px solid #353535;
+  border-radius: 50%;
+  background: linear-gradient(145deg, #dbdbdb, #eeeeee);
+  cursor: grab;
+  touch-action: none;
+  user-select: none;
+}
+
+.knob-ring {
+  position: absolute;
+  inset: 24px;
+  border-radius: 50%;
+  background: #d8d8d8;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+}
+
+.knob-core {
+  width: 82%;
+  height: 82%;
+  border-radius: 50%;
+  background: linear-gradient(135deg, #191919, #242424);
+  position: relative;
+  transform-origin: center;
+  transform: rotate(var(--knob-angle));
+}
+
+.knob.is-dragging {
+  cursor: grabbing;
+}
+
+.knob.is-locked {
+  opacity: 0.72;
+  cursor: default;
+}
+
+.indicator {
+  position: absolute;
+  top: 16px;
+  left: 24px;
+  width: 8px;
+  height: 8px;
+  border-radius: 50%;
+}
+
+.knob-pink .indicator {
+  background: #ea8bff;
+}
+
+.knob-scale {
+  position: absolute;
+  inset: -28px;
+  pointer-events: none;
+}
+
+.knob-label {
+  position: absolute;
+  transform: translate(-50%, -50%);
+  font-size: 1rem;
+  line-height: 1;
+  color: #2f2f2f;
+}
+
+.knob-green .indicator {
+  background: #8cffaf;
+}
+
+.knob-blue .indicator {
+  background: #78bcff;
+}
+
+.buttons {
+  width: min(320px, 40%);
+  min-width: 320px;
+  height: 230px;
+  border: 6px solid #222;
+  border-radius: 40px;
+  background: #191919;
+  display: grid;
+  grid-template-columns: 112px 1fr;
+  grid-template-rows: 1fr 1fr;
+  gap: 8px;
+  overflow: hidden;
+}
+
+.button {
+  background: linear-gradient(90deg, #d4d4d4, #ececec);
+  color: #2b2b2b;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+  font-size: 1rem;
+  border-radius: 28px;
+}
+
+.tab {
+  grid-column: 1;
+  grid-row: 1;
+}
+
+.shift {
+  grid-column: 1;
+  grid-row: 2;
+}
+
+.space {
+  grid-column: 2;
+  grid-row: 1 / span 2;
+  font-size: 1  rem;
+}
+
+.audio-visual {
+  display: none;
+}
+
+@media (max-width: 1200px) {
+  .screen-bar {
+    grid-template-columns: 1fr;
+    gap: 24px;
+    padding: 24px 24px 0;
+  }
+
+  .timer,
+  .screen-controls {
+    justify-self: start;
+  }
+
+  .timer {
+    font-size: 3rem;
+  }
+
+  .stats {
+    flex-wrap: wrap;
+    gap: 14px 24px;
+  }
+
+  .screen-controls {
+    width: 100%;
+  }
+
+  .timeline {
+    left: 20px;
+    right: 20px;
+    bottom: 18px;
+    padding: 24px 18px 14px;
+  }
+
+  .timeline-track {
+    font-size: 0.9rem;
+  }
+}

