+  border-radius: 999px;
+  transform: translateX(-50%);
+  background: rgba(255, 255, 255, 0.102);
+  color: rgba(255, 255, 255, 0.82);
+  font-size: 0.8rem;
+  text-align: center;
+  backdrop-filter: blur(10px);
+  -webkit-backdrop-filter: blur(10px);
+  pointer-events: none;
+}
+
+.stats {
+  display: flex;
+  flex-direction: column;
+  justify-self: start;
+  gap: 6px;
+  font-size: 0.8rem;
+}
+
+.stat-pink {
+  color: hsl(289, 100%, 87%);
+}
+
+.stat-green {
+  color: #b0ffbe;
+}
+
+.stat-blue {
+  color: #9cd1ff;
+}
+
+.status {
+  justify-self: center;
+  text-align: center;
+  font-size: 1.5rem;
+  font-weight: 400;
+  letter-spacing: 0.02em;
+  line-height: 1;
+}
+
+.screen-controls {
+  justify-self: end;
+  display: flex;
+  flex-direction: column;
+  align-items: stretch;
+  gap: 10px;
+}
+
+.archive-toggle {
+  display: inline-flex;
+  align-items: center;
+  gap: 16px;
+  border: 0;
+  padding: 0;
+  background: transparent;
+}
+
+.archive-toggle__switch {
+  position: relative;
+  width: 32px;
+  height: 18px;
+  border-radius: 999px;
+  background: #ffffff4a;
+  transition: background-color 160ms ease, box-shadow 160ms ease;
+}
+
+.archive-toggle__thumb {
+  position: absolute;
+  top: 1px;
+  left: 1px;
+  width: 16px;
+  height: 16px;
+  border-radius: 50%;
+  background: #000000;
+  transition: transform 160ms ease, background-color 160ms ease;
+}
+
+.archive-toggle__label {
+  color: rgb(255, 255, 255);
+  font-size: 1.1rem;
+  line-height: 1;
+}
+
+.archive-hint {
