+
+.archive-hint::before,
+.archive-hint::after {
+  content: "";
+  position: absolute;
+  left: 50%;
+  top: 0;
+  background: rgba(255, 255, 255, 0.78);
+  transform: translateX(-50%);
+}
+
+.archive-hint::before {
+  width: 6px;
+  height: 30px;
+  border-radius: 999px;
+}
+
+.archive-hint::after {
