+  height: 18px;
+  background: transparent;
+  border-top: 6px solid rgba(255, 255, 255, 0.78);
+  border-left: 6px solid rgba(255, 255, 255, 0.78);
+  transform: translateX(-50%) rotate(45deg);
+}
+
+.archive-hint.is-pulsing {
