+  opacity: 0.9;
+}
+
+.archive-card__duration {
+  display: inline-flex;
+  align-items: center;
+  gap: 8px;
+  color: rgba(255, 255, 255, 0.6);
+  font-size: 14px;
+  line-height: 1;
+}
+
+.archive-card__clock {
+  width: 14px;
+  height: 14px;
+  border-radius: 50%;
+  border: 2px solid currentColor;
+  position: relative;
+}
+
+.archive-card__clock::before,
+.archive-card__clock::after {
+  content: "";
+  position: absolute;
+  left: 50%;
+  top: 50%;
+  background: currentColor;
+  transform-origin: bottom center;
+}
+
+@keyframes heroArrowFloat {
+  0%,
+  100% {
+    transform: rotate(45deg) translateY(0);
+    opacity: 0.45;
+  }
+
+  50% {
+    transform: rotate(45deg) translateY(8px);
+    opacity: 1;
+  }
+}
+
+.archive-card__clock::before {
+  width: 2px;
+  height: 4px;
+  transform: translate(-50%, -100%);
+}
+
+.archive-card__clock::after {
+  width: 4px;
+  height: 2px;
+  transform: translate(0, -50%);
+}
+
+.screen.is-archive-open .archive-panel {
+  opacity: 1;
+  transform: translateX(0);
+  pointer-events: auto;
+}
+
+.volume {
+  display: flex;
+  align-items: center;
+  gap: 16px;
+}
+
+.volume-icon {
+  position: relative;
+  width: 10px;
+  height: 10px;
+  flex: 0 0 auto;
+}
+
+.volume-icon::before {
+  content: "";
+  position: absolute;
+  left: 0;
+  top: 0px;
+  width: 8px;
+  height: 10px;
+  background: #7e7e7e;
+  clip-path: polygon(0 25%, 55% 25%, 100% 0, 100% 100%, 55% 75%, 0 75%);
+}
+
+.volume-icon::after {
+  content: "";
+  position: absolute;
+  left: 10px;
+  top: -2px;
