+  z-index: 2;
+}
+
+.timeline-track {
+  position: relative;
+  display: grid;
+  grid-template-columns: auto repeat(6, 1fr auto);
+  align-items: end;
+  color: rgba(255, 255, 255, 0.52);
+  font-size: 1rem;
+}
+
+.tick-label {
+  position: relative;
+  z-index: 1;
+}
+
+.tick-gap {
+  position: relative;
+  min-width: 110px;
+  height: 14px;
+  margin: 0 8px 3px;
+}
+
+.tick-gap::before,
+.tick-gap::after {
+  content: "";
+  position: absolute;
+  top: 3px;
+  width: 2px;
+  height: 6px;
+  border-radius: 999px;
+  background: rgba(255, 255, 255, 0.52);
+}
+
+.tick-gap::before {
+  left: calc(15% - 1px);
+  box-shadow: 40px 0 0 rgba(255, 255, 255, 0.52);
+}
+
+.tick-gap::after {
+  left: calc(85% - 1px);
+}
+
+.tick-label:last-child {
+  text-align: right;
+}
+
+.controls-row {
+  display: flex;
+  align-items: center;
+  justify-content: space-between;
+  gap: 40px;
+}
+
+.knobs {
+  display: flex;
+  gap: 72px;
+}
+
+.knob {
+  --knob-angle: -93.333deg;
+  position: relative;
+  width: 200px;
+  aspect-ratio: 1;
+  border: 3px solid #353535;
+  border-radius: 50%;
+  background: linear-gradient(145deg, #dbdbdb, #eeeeee);
+  cursor: grab;
+  touch-action: none;
+  user-select: none;
+}
+
+.knob-ring {
+  position: absolute;
+  inset: 24px;
+  border-radius: 50%;
+  background: #d8d8d8;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+}
+
+.knob-core {
+  width: 82%;
+  height: 82%;
+  border-radius: 50%;
+  background: linear-gradient(135deg, #191919, #242424);
+  position: relative;
+  transform-origin: center;
+  transform: rotate(var(--knob-angle));
+}
+
+.knob.is-dragging {
+  cursor: grabbing;
+}
+
+.knob.is-locked {
+  opacity: 0.72;
+  cursor: default;
+}
+
+.indicator {
+  position: absolute;
+  top: 16px;
+  left: 24px;
+  width: 8px;
+  height: 8px;
+  border-radius: 50%;
+}
+
+.knob-pink .indicator {
+  background: #ea8bff;
+}
+
+.knob-scale {
+  position: absolute;
+  inset: -28px;
+  pointer-events: none;
+}
+
+.knob-label {
+  position: absolute;
+  transform: translate(-50%, -50%);
+  font-size: 1rem;
+  line-height: 1;
+  color: #2f2f2f;
+}
+
+.knob-green .indicator {
+  background: #8cffaf;
+}
+
+.knob-blue .indicator {
+  background: #78bcff;
+}
+
+.buttons {
+  width: min(320px, 40%);
+  min-width: 320px;
+  height: 230px;
+  border: 6px solid #222;
+  border-radius: 40px;
+  background: #191919;
+  display: grid;
+  grid-template-columns: 112px 1fr;
+  grid-template-rows: 1fr 1fr;
+  gap: 8px;
+  overflow: hidden;
+}
+
+.button {
+  background: linear-gradient(90deg, #d4d4d4, #ececec);
+  color: #2b2b2b;
+  display: flex;
+  justify-content: center;
+  align-items: center;
+  font-size: 1rem;
+  border-radius: 28px;
+}
+
+.tab {
+  grid-column: 1;
+  grid-row: 1;
+}
+
+.shift {
+  grid-column: 1;
+  grid-row: 2;
+}
+
+.space {
+  grid-column: 2;
+  grid-row: 1 / span 2;
+  font-size: 1  rem;
+}
+
+.audio-visual {
+  display: none;
+}
+
+@media (max-width: 1200px) {
+  .screen-bar {
+    grid-template-columns: 1fr;
+    gap: 24px;
+    padding: 24px 24px 0;
+  }
+
+  .timer,
+  .screen-controls {
+    justify-self: start;
+  }
+
+  .timer {
+    font-size: 3rem;
+  }
+
+  .stats {
+    flex-wrap: wrap;
+    gap: 14px 24px;
+  }
+
+  .screen-controls {
+    width: 100%;
+  }
+
+  .timeline {
+    left: 20px;
+    right: 20px;
+    bottom: 18px;
+    padding: 24px 18px 14px;
+  }
+
+  .timeline-track {
+    font-size: 0.9rem;
+  }
+}

